
const PIECES = [{"title": "Cello Suite No. 1 in G major: Prelude", "composer": "Johann Sebastian Bach", "year": "c. 1720", "period": "Baroque", "duration": "~2–3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Bach%20-%20Cello%20Suite%20No.%201%20-%20Prelude.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Cello_Suite_No._1_in_G_major,_BWV_1007", "why": "It sounds simple, but it is one of the clearest examples of Bach creating architecture from a single flowing line. The cello implies harmony, movement and emotional direction almost by itself.", "listen": ["The rolling arpeggios feel like the piece is breathing.", "There is no big melody in the pop-song sense; the pattern itself becomes expressive.", "The music keeps moving forward while still feeling calm.", "Notice how the ending feels like arrival rather than just stopping."], "know": "It is one of the most recognised solo instrumental openings in classical music and a perfect doorway into Bach’s logic: emotional depth through structure.", "takeaway": "Bach can make one instrument sound like a whole building."}, {"title": "Toccata and Fugue in D minor", "composer": "Johann Sebastian Bach", "year": "early 18th century", "period": "Baroque", "duration": "~8–10 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Bach%20-%20Toccata%20and%20Fugue%20in%20D%20minor.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Toccata_and_Fugue_in_D_minor,_BWV_565", "why": "This is the organ as theatre. The opening gesture is so famous because it feels like a door being thrown open into darkness, drama and echo.", "listen": ["The opening is declamatory, almost like a voice calling out.", "The fugue turns a musical idea into overlapping imitation.", "The organ’s space and resonance are part of the effect.", "The piece alternates freedom and strict logic."], "know": "It became the shorthand for dramatic organ music in films, cartoons and popular culture, even beyond classical audiences.", "takeaway": "Baroque complexity does not have to sound polite. It can sound dangerous."}, {"title": "Brandenburg Concerto No. 3: I. Allegro", "composer": "Johann Sebastian Bach", "year": "1721", "period": "Baroque", "duration": "~5–6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Brandenburg%20Concerto%20No.%203%20in%20G%20major%2C%20BWV%201048%20-%20I.%20Allegro.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Brandenburg_Concerto_No._3_in_G_major,_BWV_1048", "why": "It is pure Baroque motion: strings passing energy back and forth with almost mechanical brilliance, but the result feels alive rather than mechanical.", "listen": ["The instruments often behave like equals rather than soloist plus background.", "Short motifs bounce around the ensemble.", "The rhythm rarely relaxes.", "The pleasure comes from pattern, speed and balance."], "know": "The Brandenburg Concertos are central to understanding Bach’s instrumental writing and Baroque concerto style.", "takeaway": "Bach turns cooperation into momentum."}, {"title": "The Four Seasons: Spring, I. Allegro", "composer": "Antonio Vivaldi", "year": "1723", "period": "Baroque", "duration": "~3–4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Vivaldi%20-%20The%20Four%20Seasons%20-%20Spring%20-%20I.%20Allegro.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:The_Four_Seasons_(Vivaldi)", "why": "Vivaldi makes the orchestra paint birds, storms, streams and sunshine. It is one of the great examples of music behaving almost like cinema before cinema existed.", "listen": ["The opening theme returns like a bright seasonal signal.", "The solo violin imitates birdsong and motion.", "Stormy passages interrupt the brightness.", "The music is vivid without needing words."], "know": "It is one of the most famous examples of program music: instrumental music that suggests a scene or story.", "takeaway": "Classical music can describe the world without literally naming it."}, {"title": "Messiah: Hallelujah Chorus", "composer": "George Frideric Handel", "year": "1741", "period": "Baroque", "duration": "~4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Handel%20-%20Messiah%20-%20Hallelujah.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Messiah_(Handel)", "why": "It is communal musical architecture: voices, orchestra and repetition building a public feeling of triumph.", "listen": ["The word Hallelujah becomes rhythm, not just text.", "The choir alternates block chords with moving lines.", "The energy feels ceremonial and public.", "The repeated phrases make the music easy to remember."], "know": "It is one of the most recognised choral pieces ever written and a pillar of English-language oratorio tradition.", "takeaway": "Repetition can turn music into collective emotion."}, {"title": "Eine kleine Nachtmusik: I. Allegro", "composer": "Wolfgang Amadeus Mozart", "year": "1787", "period": "Classical", "duration": "~5–6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mozart%20-%20Eine%20kleine%20Nachtmusik%20-%201.%20Allegro.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Eine_kleine_Nachtmusik", "why": "This is Mozart at his most instantly readable: elegant, balanced, confident and impossible to forget.", "listen": ["The opening is like a clean musical signature.", "Phrases feel balanced, almost conversational.", "Energy comes from clarity rather than heaviness.", "The music smiles, but it is not shallow."], "know": "It is one of the most famous serenades and a perfect example of Classical-era balance.", "takeaway": "Mozart’s difficulty is hidden inside ease."}, {"title": "Requiem: Lacrimosa", "composer": "Wolfgang Amadeus Mozart", "year": "1791", "period": "Classical", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mozart%20-%20Requiem%20-%20Lacrimosa.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Requiem_in_D_minor,_K._626_(Mozart)", "why": "Lacrimosa is grief made formal. It does not collapse into chaos; it moves with ritual weight.", "listen": ["The choir enters with a sighing, falling gesture.", "The rhythm feels like a funeral procession.", "The harmony darkens the emotional colour.", "The music is short but devastating."], "know": "Mozart died before completing the Requiem, which adds to the mythology around the work.", "takeaway": "Sad music becomes stronger when it has discipline."}, {"title": "Symphony No. 40 in G minor: I. Molto allegro", "composer": "Wolfgang Amadeus Mozart", "year": "1788", "period": "Classical", "duration": "~7–8 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mozart%20Symphony%2040%201st%20movement.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Symphony_No._40_in_G_minor,_K._550_(Mozart)", "why": "This is Mozart with shadows. The melody is beautiful, but restless and anxious rather than decorative.", "listen": ["The opening accompaniment trembles under the melody.", "The main theme feels urgent and unsettled.", "Classical balance is still there, but under pressure.", "The minor key gives the whole movement nervous energy."], "know": "It is one of Mozart’s most famous symphonies and a key example of emotional intensity inside Classical form.", "takeaway": "Mozart is not only elegance. He can be deeply uneasy."}, {"title": "Symphony No. 5: I. Allegro con brio", "composer": "Ludwig van Beethoven", "year": "1808", "period": "Classical / Romantic transition", "duration": "~7–8 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Beethoven%20-%20Symphony%20No.%205%20-%201st%20movement.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Symphony_No._5_(Beethoven)", "why": "Those four notes are famous, but the genius is how Beethoven turns a tiny rhythm into an entire argument.", "listen": ["The short-short-short-long rhythm keeps returning.", "The orchestra feels like it is wrestling with one idea.", "Silence is used like pressure.", "The movement feels inevitable."], "know": "It is one of the most important symphonic openings in Western music and a defining Beethoven statement.", "takeaway": "Great music often needs one idea with consequences."}, {"title": "Symphony No. 9: Ode to Joy", "composer": "Ludwig van Beethoven", "year": "1824", "period": "Romantic transition", "duration": "~20+ min finale", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Beethoven%20-%20Symphony%20No.%209%20-%20Ode%20to%20Joy.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Symphony_No._9_(Beethoven)", "why": "Beethoven brings human voices into the symphony and turns a melody into a public ideal of joy, brotherhood and aspiration.", "listen": ["The famous theme is simple enough to sing.", "The finale feels like it is searching before it arrives.", "Soloists and choir expand the symphonic world.", "The music tries to sound universal."], "know": "Its melody became a cultural symbol far beyond the concert hall, including as the anthem of Europe.", "takeaway": "Beethoven makes private struggle sound public."}, {"title": "Piano Sonata No. 14: Moonlight Sonata, I. Adagio sostenuto", "composer": "Ludwig van Beethoven", "year": "1801", "period": "Classical / Romantic transition", "duration": "~5–6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Beethoven%20-%20Moonlight%20Sonata%20-%201st%20movement.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Piano_Sonata_No._14_(Beethoven)", "why": "Instead of opening with display, Beethoven creates suspended, nocturnal inwardness. It feels less like a sonata showing off and more like a private state of mind.", "listen": ["The triplet pattern keeps flowing underneath.", "The melody is restrained, almost half-hidden.", "The mood is still but emotionally charged.", "The piece avoids obvious drama while creating deep tension."], "know": "It is one of the most famous piano movements ever written and a gateway into Beethoven’s introspective side.", "takeaway": "Quiet does not mean weak. Quiet can be pressure."}, {"title": "Für Elise", "composer": "Ludwig van Beethoven", "year": "1810", "period": "Classical / Romantic transition", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Beethoven%20-%20F%C3%BCr%20Elise.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Für_Elise", "why": "It is famous because the opening is intimate, memorable and playable enough to become part of everyday musical culture.", "listen": ["The opening alternates tenderness and hesitation.", "The main idea keeps returning after contrasting episodes.", "It feels personal rather than grand.", "Its simplicity is part of its staying power."], "know": "It is probably one of the first Beethoven pieces many people recognise or try to play.", "takeaway": "A small piece can become culturally enormous."}, {"title": "Piano Sonata No. 8: Pathétique, II. Adagio cantabile", "composer": "Ludwig van Beethoven", "year": "1798", "period": "Classical / Romantic transition", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Beethoven%20-%20Piano%20Sonata%20No.%208%20-%202.%20Adagio%20cantabile.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Piano_Sonata_No._8_(Beethoven)", "why": "This movement shows Beethoven’s gift for direct lyrical beauty without becoming sentimental.", "listen": ["The melody sings like an aria.", "The accompaniment supports rather than distracts.", "The mood is noble and intimate.", "The return of the theme feels comforting."], "know": "It is one of Beethoven’s most loved slow movements and a key example of piano lyricism.", "takeaway": "Beethoven can be tender without losing strength."}, {"title": "Nocturne in E-flat major, Op. 9 No. 2", "composer": "Frédéric Chopin", "year": "1830–1832", "period": "Romantic", "duration": "~4–5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Chopin%20-%20Nocturne%20op.%209%20no.%202.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Nocturne_in_E-flat_major,_Op._9,_No._2_(Chopin)", "why": "Chopin makes the piano sing. The piece feels intimate because the melody breathes like a human voice.", "listen": ["The right hand melody decorates itself with graceful turns.", "The left hand rocks gently underneath.", "The tempo should feel flexible, not mechanical.", "The mood is elegant but vulnerable."], "know": "It is one of the most famous piano nocturnes and a perfect introduction to Romantic piano language.", "takeaway": "Chopin turns ornament into emotion."}, {"title": "Prelude in D-flat major, Op. 28 No. 15: Raindrop", "composer": "Frédéric Chopin", "year": "1838–1839", "period": "Romantic", "duration": "~5–6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Chopin%20-%20Prelude%20Op.%2028%20No.%2015%20Raindrop.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Prelude_in_D-flat_major,_Op._28,_No._15_(Chopin)", "why": "The repeated note gives the piece its nickname, but the real power is the shift from calm surface to darker inner weather.", "listen": ["A repeated note quietly persists through much of the piece.", "The middle section becomes darker and heavier.", "The opening calm returns changed by what happened.", "The piano creates atmosphere with very little material."], "know": "It is one of Chopin’s most accessible examples of Romantic atmosphere and transformation.", "takeaway": "A tiny repeated detail can become emotional weather."}, {"title": "Funeral March from Piano Sonata No. 2", "composer": "Frédéric Chopin", "year": "1839", "period": "Romantic", "duration": "~8–9 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Chopin%20-%20Funeral%20March.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Piano_Sonata_No._2_(Chopin)", "why": "This is one of the most recognisable musical images of death: heavy, ceremonial, unforgettable.", "listen": ["The dotted rhythm suggests a funeral procession.", "The outer sections are severe and dark.", "The middle section is softer, almost like memory.", "The return of the march feels unavoidable."], "know": "It became a cultural shorthand for mourning far beyond classical music.", "takeaway": "Music can become a public symbol of an emotion."}, {"title": "Liebesträume No. 3", "composer": "Franz Liszt", "year": "1850", "period": "Romantic", "duration": "~4–5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Liszt%20-%20Liebestraum%20No.%203.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Liebesträume,_S.541_(Liszt)", "why": "Liszt combines lyrical tenderness with pianistic glamour. It is romantic in both the musical and everyday sense.", "listen": ["The melody should feel like it is floating above the accompaniment.", "The middle grows more passionate and virtuosic.", "The piece returns to intimacy after display.", "Listen for the balance between singing line and shimmering texture."], "know": "It is one of Liszt’s most beloved piano pieces and a good counterweight to his reputation for pure virtuosity.", "takeaway": "Virtuosity is most powerful when it serves feeling."}, {"title": "Hungarian Rhapsody No. 2", "composer": "Franz Liszt", "year": "1847", "period": "Romantic", "duration": "~10 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Liszt%20-%20Hungarian%20Rhapsody%20No.%202.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Hungarian_Rhapsody_No._2", "why": "It is flamboyant, theatrical and full of contrast. Liszt turns the piano into a stage.", "listen": ["The opening feels dramatic and improvisatory.", "Slow material gives way to fast dance energy.", "The pianist becomes almost orchestral.", "The ending is designed to dazzle."], "know": "It became famous in concert culture and popular media, including cartoons.", "takeaway": "Sometimes classical music absolutely wants to show off."}, {"title": "Ave Maria", "composer": "Franz Schubert", "year": "1825", "period": "Romantic", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Schubert%20-%20Ave%20Maria.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Ave_Maria_(Schubert)", "why": "Schubert’s gift is melody that seems inevitable. This piece feels devotional, but also deeply human.", "listen": ["The melody unfolds simply and gracefully.", "The accompaniment rocks gently underneath.", "The emotional power comes from restraint.", "The line feels like a prayer in sound."], "know": "It is one of Schubert’s most famous songs and a staple of sacred and concert performance.", "takeaway": "Schubert can make melody feel like breathing."}, {"title": "Erlkönig", "composer": "Franz Schubert", "year": "1815", "period": "Romantic", "duration": "~4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Schubert%20-%20Erlk%C3%B6nig.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Erlkönig_(Schubert)", "why": "Schubert compresses a supernatural drama into one singer and piano. It is storytelling under extreme pressure.", "listen": ["The piano gallops from the first second.", "The singer shifts between narrator, father, child and Erlking.", "The tension keeps rising.", "The ending lands with brutal finality."], "know": "It is one of the defining German art songs and a brilliant example of text painting.", "takeaway": "A song can be a full drama if the composer knows where to put pressure."}, {"title": "The Trout Quintet: IV. Theme and Variations", "composer": "Franz Schubert", "year": "1819", "period": "Romantic", "duration": "~8 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Schubert%20-%20Trout%20Quintet%20-%204th%20movement.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Piano_Quintet_in_A_major,_D._667_(Schubert)", "why": "Schubert turns a song-like theme into a series of fresh characters without losing charm.", "listen": ["The main tune is clear and friendly.", "Each variation changes colour or texture.", "The unusual ensemble gives warmth.", "The music feels social and relaxed."], "know": "It is one of the best-loved chamber works and an easy entry into variation form.", "takeaway": "Variation is not repetition. It is personality change."}, {"title": "Wedding March from A Midsummer Night’s Dream", "composer": "Felix Mendelssohn", "year": "1842", "period": "Romantic", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mendelssohn%20-%20Wedding%20March.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:A_Midsummer_Night's_Dream_(Mendelssohn)", "why": "It became one of the default sounds of weddings because it turns ceremony into bright, public confidence.", "listen": ["The opening fanfare is instantly ceremonial.", "The rhythm feels processional.", "The orchestration sparkles rather than weighs down.", "The piece balances grandeur and joy."], "know": "It is one of the most culturally embedded pieces of classical music, even among people who do not know its title.", "takeaway": "Some music escapes the concert hall and becomes social ritual."}, {"title": "Spring Song", "composer": "Felix Mendelssohn", "year": "1842", "period": "Romantic", "duration": "~2–3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mendelssohn%20-%20Spring%20Song.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Lieder_ohne_Worte_(Mendelssohn)", "why": "It is light, graceful and perfectly formed. Mendelssohn makes the piano sound like an effortless song without words.", "listen": ["The melody sits gently above a flowing accompaniment.", "The mood is bright but not loud.", "Phrases feel balanced and polished.", "The charm comes from clarity."], "know": "It is one of the most famous pieces from Mendelssohn’s Songs Without Words.", "takeaway": "A piece can be small and still perfectly designed."}, {"title": "Hungarian Dance No. 5", "composer": "Johannes Brahms", "year": "1869", "period": "Romantic", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Brahms%20-%20Hungarian%20Dance%20No.%205.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Hungarian_Dance_No._5_(Brahms)", "why": "It is all character: sudden tempo changes, dance energy and theatrical flair.", "listen": ["The tempo pushes and pulls dramatically.", "The main tune is bold and memorable.", "The music alternates swagger and delicacy.", "Rhythmic surprise is the point."], "know": "It is Brahms’s most famous Hungarian Dance and one of his most widely recognised melodies.", "takeaway": "Classical dance music often lives in the tension between control and impulse."}, {"title": "Symphony No. 3: III. Poco allegretto", "composer": "Johannes Brahms", "year": "1883", "period": "Romantic", "duration": "~6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Brahms%20-%20Symphony%20No.%203%20-%203rd%20movement.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Symphony_No._3_(Brahms)", "why": "This is Brahms at his autumnal best: restrained, melancholy, noble and deeply memorable.", "listen": ["The main melody is warm but sad.", "The rhythm avoids obvious drama.", "The orchestration has a dark glow.", "The emotion feels mature rather than theatrical."], "know": "It is one of Brahms’s most famous symphonic movements and often appears in film and popular culture.", "takeaway": "Brahms makes nostalgia sound dignified."}, {"title": "Swan Lake: Scene", "composer": "Pyotr Ilyich Tchaikovsky", "year": "1875–1876", "period": "Romantic", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Tchaikovsky%20-%20Swan%20Lake%20-%20Scene.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Swan_Lake", "why": "Tchaikovsky creates ballet music that works even without dancers: melody, atmosphere and tragic elegance all at once.", "listen": ["The oboe melody feels fragile and haunted.", "Strings create a dark lake-like atmosphere.", "The music suggests movement without needing to see it.", "Beauty and sadness are inseparable."], "know": "Swan Lake is one of the most famous ballets in the world and a defining example of Romantic ballet music.", "takeaway": "Great ballet music should make you see movement with your ears."}, {"title": "1812 Overture", "composer": "Pyotr Ilyich Tchaikovsky", "year": "1880", "period": "Romantic", "duration": "~15 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Tchaikovsky%20-%201812%20Overture.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:1812_Overture", "why": "It is famous for spectacle: hymns, battle references, bells and cannons. Subtle it is not. Effective it absolutely is.", "listen": ["The opening is solemn and hymn-like.", "Military rhythms build tension.", "Recognisable tunes collide symbolically.", "The ending is designed as a public explosion."], "know": "It is one of the most famous orchestral showpieces and a classic example of music as historical theatre.", "takeaway": "Sometimes music is not trying to be intimate. It is trying to blow the doors open."}, {"title": "The Nutcracker: Dance of the Sugar Plum Fairy", "composer": "Pyotr Ilyich Tchaikovsky", "year": "1892", "period": "Romantic", "duration": "~2 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Tchaikovsky%20-%20Dance%20of%20the%20Sugar%20Plum%20Fairy.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:The_Nutcracker", "why": "The celesta gives the music its magical, glassy sound. Tchaikovsky makes timbre the star.", "listen": ["The celesta sounds bell-like and delicate.", "The melody is strange, not just sweet.", "The orchestra creates a miniature fantasy world.", "The rhythm feels like careful tiny steps."], "know": "It introduced many listeners to the celesta and became one of the most famous ballet excerpts ever.", "takeaway": "Sometimes the instrument choice is the hook."}, {"title": "New World Symphony: II. Largo", "composer": "Antonín Dvořák", "year": "1893", "period": "Romantic", "duration": "~12 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Dvorak%20-%20Symphony%20No.%209%20-%202nd%20movement.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Symphony_No._9_(Dvořák)", "why": "The English horn melody feels like homesickness translated into sound. It is simple, spacious and deeply affecting.", "listen": ["The opening brass chords feel like a doorway.", "The English horn sings the famous melody.", "The movement balances longing and calm.", "The orchestration leaves room for silence."], "know": "Written while Dvořák was in America, it became one of the most beloved symphonic slow movements.", "takeaway": "A simple melody can carry an entire emotional landscape."}, {"title": "Slavonic Dance Op. 46 No. 8", "composer": "Antonín Dvořák", "year": "1878", "period": "Romantic", "duration": "~4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Dvorak%20-%20Slavonic%20Dance%20Op.%2046%20No.%208.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Slavonic_Dances", "why": "Dvořák turns folk-dance energy into polished concert music without draining its vitality.", "listen": ["Rhythmic accents give the music bounce.", "The orchestra feels colourful and physical.", "Fast passages alternate with broader gestures.", "The dance character drives everything."], "know": "The Slavonic Dances helped make Dvořák internationally famous.", "takeaway": "National style can become concert-hall electricity."}, {"title": "Clair de lune", "composer": "Claude Debussy", "year": "1890 / revised 1905", "period": "Impressionism", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Debussy%20-%20Clair%20de%20lune.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Clair_de_lune_(Debussy)", "why": "Debussy does not push emotion at you. He lets harmony, colour and resonance create moonlit ambiguity.", "listen": ["The opening feels suspended rather than directional.", "Harmony creates colour more than tension-release logic.", "The middle grows more fluid and luminous.", "Silence and resonance matter."], "know": "It is one of the most famous piano pieces associated with musical Impressionism.", "takeaway": "Debussy teaches you to listen for colour, not just tune."}, {"title": "Prélude à l'après-midi d'un faune", "composer": "Claude Debussy", "year": "1894", "period": "Impressionism", "duration": "~10 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Debussy%20-%20Prelude%20to%20the%20Afternoon%20of%20a%20Faun.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Prélude_à_l'après-midi_d'un_faune", "why": "The opening flute line changed music’s sense of time and atmosphere. It drifts, seduces and refuses old-fashioned square phrasing.", "listen": ["The flute opening feels fluid and uncertain.", "The orchestra shimmers rather than declares.", "Harmony behaves like scent or light.", "The piece is more atmosphere than plot."], "know": "It is often treated as a turning point toward musical modernism.", "takeaway": "Modern music begins partly when direction becomes atmosphere."}, {"title": "Gymnopédie No. 1", "composer": "Erik Satie", "year": "1888", "period": "Late Romantic / Modernist precursor", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Satie%20-%20Gymnopedie%20No.%201.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Gymnopédies", "why": "Satie strips music down until it feels almost weightless. It is simple, strange and emotionally hard to pin down.", "listen": ["The rhythm is slow and steady.", "The melody feels detached, almost floating.", "The harmony has quiet surprises.", "The piece resists drama."], "know": "It influenced later ideas of minimalism, ambient music and modern simplicity.", "takeaway": "Simple music can be mysterious, not basic."}, {"title": "Gnossienne No. 1", "composer": "Erik Satie", "year": "1890", "period": "Late Romantic / Modernist precursor", "duration": "~3–4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Satie%20-%20Gnossienne%20No.%201.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Gnossiennes", "why": "It feels ancient, modern, ironic and sincere at the same time. Satie refuses obvious emotional instructions.", "listen": ["The melody has an exotic, modal flavour.", "There are no bar lines in the original notation.", "The left hand accompaniment is sparse and hypnotic.", "The mood feels detached but not empty."], "know": "It is one of Satie’s most recognisable pieces and a doorway into musical minimalism before minimalism.", "takeaway": "Ambiguity can be more addictive than drama."}, {"title": "Boléro", "composer": "Maurice Ravel", "year": "1928", "period": "Modern / Impressionist-adjacent", "duration": "~15 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Ravel%20-%20Bolero.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Boléro_(Ravel)", "why": "Boléro is a controlled obsession: one rhythm, one melody, one long crescendo. The drama is not development, but accumulation.", "listen": ["The snare drum rhythm barely stops.", "The melody passes through different instruments.", "The volume and orchestration grow gradually.", "The ending feels like pressure finally breaking."], "know": "It is one of the most famous orchestral pieces of the twentieth century, partly because its concept is so clear.", "takeaway": "Repetition can be suspense."}, {"title": "Pavane pour une infante défunte", "composer": "Maurice Ravel", "year": "1899", "period": "Impressionism / Modern", "duration": "~6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Ravel%20-%20Pavane%20pour%20une%20infante%20d%C3%A9funte.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Pavane_pour_une_infante_défunte", "why": "Ravel creates elegance without excess. The piece feels nostalgic, formal and emotionally distant in a beautiful way.", "listen": ["The melody moves slowly and ceremonially.", "The harmony gives the old dance form modern colour.", "The emotion is restrained.", "The pacing matters more than drama."], "know": "It is one of Ravel’s best-known shorter works and a good example of refined French musical colour.", "takeaway": "Elegance can be emotional because it holds back."}, {"title": "The Planets: Mars, the Bringer of War", "composer": "Gustav Holst", "year": "1914–1917", "period": "Modern / Late Romantic", "duration": "~7 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Holst%20-%20The%20Planets%20-%20Mars.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:The_Planets_(Holst)", "why": "Mars is war as rhythm. Its pounding irregular meter and brutal orchestration influenced countless film scores.", "listen": ["The repeated rhythm feels mechanical and threatening.", "Brass and percussion create violence without literal battle sounds.", "The music grows in waves of pressure.", "The meter feels unstable and relentless."], "know": "It is one of the most influential orchestral depictions of war in modern music.", "takeaway": "Rhythm can be terrifying."}, {"title": "The Planets: Jupiter, the Bringer of Jollity", "composer": "Gustav Holst", "year": "1914–1917", "period": "Modern / Late Romantic", "duration": "~8 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Holst%20-%20The%20Planets%20-%20Jupiter.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:The_Planets_(Holst)", "why": "Jupiter combines festive energy with one of Holst’s most noble melodies. It is public joy with grandeur.", "listen": ["Fast outer sections bounce with orchestral colour.", "The big central melody broadens the emotional scale.", "The music alternates playfulness and ceremony.", "The orchestration feels generous."], "know": "The central melody became the hymn tune Thaxted and is widely recognised in Britain.", "takeaway": "Joy can be both playful and noble."}, {"title": "The Rite of Spring: Introduction and Augurs of Spring", "composer": "Igor Stravinsky", "year": "1913", "period": "Modernism", "duration": "~7–8 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Stravinsky%20-%20The%20Rite%20of%20Spring%20-%20Introduction%20and%20Augurs.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:The_Rite_of_Spring", "why": "This music helped blow open the twentieth century. Rhythm becomes savage, harmony becomes raw, and ballet becomes ritual shock.", "listen": ["The high bassoon opening sounds strange and ancient.", "The repeated chords hit like physical blows.", "Accents fall unpredictably.", "The orchestra feels percussive and primal."], "know": "Its 1913 premiere is one of the most famous scandals in music history.", "takeaway": "Modernism often begins by making the audience lose its balance."}, {"title": "Firebird Suite: Finale", "composer": "Igor Stravinsky", "year": "1910 / suite versions later", "period": "Modernism", "duration": "~3–4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Stravinsky%20-%20Firebird%20Suite%20-%20Finale.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:The_Firebird", "why": "The Finale rises from quiet magic to blazing orchestral triumph. It is one of Stravinsky’s most accessible moments.", "listen": ["The opening horn melody feels distant and mythical.", "Layers gradually accumulate.", "The orchestration brightens into a huge climax.", "The ending feels like transformation."], "know": "The Firebird made Stravinsky internationally famous before The Rite of Spring shocked audiences.", "takeaway": "Stravinsky could dazzle before he detonated."}, {"title": "Carmen: Habanera", "composer": "Georges Bizet", "year": "1875", "period": "Romantic", "duration": "~4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Bizet%20-%20Carmen%20-%20Habanera.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Carmen_(Bizet)", "why": "The Habanera defines character through rhythm. Carmen’s music is seductive, self-possessed and rhythmically unforgettable.", "listen": ["The habanera rhythm gives the aria its sway.", "The melody moves chromatically downward.", "Carmen sounds in control of the room.", "The chorus responses create public tension."], "know": "It is one of the most famous opera arias ever written.", "takeaway": "A character can enter through rhythm before plot."}, {"title": "Carmen: Toreador Song", "composer": "Georges Bizet", "year": "1875", "period": "Romantic", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Bizet%20-%20Carmen%20-%20Toreador%20Song.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Carmen_(Bizet)", "why": "The Toreador Song is opera as public charisma: swagger, chorus, masculinity and spectacle.", "listen": ["The march-like rhythm gives confidence.", "The melody is designed to be remembered.", "The chorus amplifies the social atmosphere.", "The music is theatrical rather than introspective."], "know": "It is one of the most recognisable baritone arias in the opera repertory.", "takeaway": "Opera knows how to weaponise confidence."}, {"title": "The Barber of Seville: Largo al factotum", "composer": "Gioachino Rossini", "year": "1816", "period": "Bel canto / Classical-Romantic", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Rossini%20-%20Largo%20al%20factotum.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Il_barbiere_di_Siviglia_(Rossini)", "why": "Figaro explodes onto the stage with comic confidence. It is one of opera’s great self-introductions.", "listen": ["The patter writing demands speed and clarity.", "Figaro’s repeated name becomes a comic hook.", "The orchestra keeps the energy buoyant.", "The aria is personality in motion."], "know": "It is one of the most famous comic opera arias and a test of baritone agility.", "takeaway": "A great entrance tells you who someone is before the plot explains it."}, {"title": "William Tell Overture: Finale", "composer": "Gioachino Rossini", "year": "1829", "period": "Romantic", "duration": "~3–4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Rossini%20-%20William%20Tell%20Overture%20-%20Finale.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:William_Tell_Overture", "why": "The galloping finale became one of the most famous musical images of speed and pursuit.", "listen": ["The rhythm suggests horse-riding momentum.", "Brass and strings create bright excitement.", "The music is direct and physical.", "It keeps pushing forward."], "know": "It became a staple of popular culture, especially through radio, film and cartoons.", "takeaway": "Sometimes the orchestra just wants to run."}, {"title": "Nessun dorma", "composer": "Giacomo Puccini", "year": "1924", "period": "Late Romantic / Verismo", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Puccini%20-%20Nessun%20dorma.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Nessun_dorma", "why": "Puccini builds from intimacy to a final high point that feels inevitable and public.", "listen": ["The opening is quiet and controlled.", "The melody gradually opens outward.", "The final Vincero is the emotional target.", "The orchestra supports the voice like a wave."], "know": "It became one of the most famous tenor arias in the world, especially through twentieth-century recordings and sporting events.", "takeaway": "Puccini understood the emotional power of the final note."}, {"title": "Madama Butterfly: Un bel dì vedremo", "composer": "Giacomo Puccini", "year": "1904", "period": "Late Romantic / Verismo", "duration": "~4–5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Puccini%20-%20Un%20bel%20di%20vedremo.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Madama_Butterfly", "why": "Puccini makes hope heartbreaking because we can hear how fragile it is.", "listen": ["The vocal line begins with controlled imagination.", "The orchestra paints the scene she describes.", "The aria grows in emotional intensity.", "Hope and denial sit together."], "know": "It is one of the central soprano arias of the Italian opera repertory.", "takeaway": "Opera can make self-deception sound beautiful."}, {"title": "Ride of the Valkyries", "composer": "Richard Wagner", "year": "1856", "period": "Romantic", "duration": "~5 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Wagner%20-%20Ride%20of%20the%20Valkyries.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Ride_of_the_Valkyries", "why": "Wagner creates mythic motion with brass, rhythm and vocal force. It sounds airborne and unstoppable.", "listen": ["The famous theme rises like a charge.", "Brass dominate the heroic colour.", "The rhythm creates galloping flight.", "The voices add mythic scale."], "know": "It is one of Wagner’s most famous excerpts and has been used extensively in film and media.", "takeaway": "Wagner makes mythology sound like machinery in the sky."}, {"title": "Tristan und Isolde: Prelude", "composer": "Richard Wagner", "year": "1859", "period": "Romantic", "duration": "~10 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Wagner%20-%20Tristan%20und%20Isolde%20-%20Prelude.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Tristan_und_Isolde", "why": "The famous Tristan chord helped stretch harmony toward modern music. Desire here is unresolved by design.", "listen": ["The opening chord does not settle normally.", "Phrases reach, ache and delay resolution.", "The music breathes in long waves.", "Tension is the main substance."], "know": "It is one of the key works in the history of harmony and musical modernity.", "takeaway": "Wagner made longing into a harmonic system."}, {"title": "Morning Mood from Peer Gynt", "composer": "Edvard Grieg", "year": "1875", "period": "Romantic", "duration": "~4 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Grieg%20-%20Peer%20Gynt%20-%20Morning%20Mood.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Peer_Gynt_(Grieg)", "why": "It is sunrise music so successful that it became the default sound of morning in popular culture.", "listen": ["The flute and oboe gently open the scene.", "The melody rises like light.", "The orchestra gradually warms.", "The simplicity is part of the charm."], "know": "It is one of Grieg’s most famous orchestral pieces and a major example of incidental music escaping the play.", "takeaway": "Music can become a shared image of a time of day."}, {"title": "In the Hall of the Mountain King", "composer": "Edvard Grieg", "year": "1875", "period": "Romantic", "duration": "~3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Grieg%20-%20In%20the%20Hall%20of%20the%20Mountain%20King.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:In_the_Hall_of_the_Mountain_King", "why": "One tiny idea grows into manic chaos. It is one of the clearest examples of acceleration and accumulation.", "listen": ["The theme starts quietly and low.", "It repeats while getting faster and louder.", "Orchestration adds menace and comedy.", "The ending feels like a chase losing control."], "know": "It is instantly recognisable from film, television and cartoons.", "takeaway": "Repetition plus acceleration equals panic."}, {"title": "Scheherazade: The Sea and Sinbad’s Ship", "composer": "Nikolai Rimsky-Korsakov", "year": "1888", "period": "Romantic / Russian nationalist", "duration": "~10 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Rimsky-Korsakov%20-%20Scheherazade%20-%201.%20The%20Sea%20and%20Sinbad%27s%20Ship.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Scheherazade_(Rimsky-Korsakov)", "why": "Rimsky-Korsakov turns the orchestra into a storytelling machine full of colour, sea motion and exotic fantasy.", "listen": ["The opening brass theme sounds stern and royal.", "The solo violin represents Scheherazade’s voice.", "The sea is suggested through rocking orchestral motion.", "Colour changes constantly."], "know": "It is one of the great orchestral showpieces of Russian Romanticism.", "takeaway": "Orchestration can be storytelling."}, {"title": "Flight of the Bumblebee", "composer": "Nikolai Rimsky-Korsakov", "year": "1899–1900", "period": "Romantic / Russian nationalist", "duration": "~1–2 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Rimsky-Korsakov%20-%20Flight%20of%20the%20Bumblebee.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Flight_of_the_Bumblebee", "why": "It is famous because it turns speed into character. The music buzzes, darts and refuses to sit still.", "listen": ["Chromatic runs create the buzzing effect.", "The line barely stops for breath.", "Virtuosity is part of the joke.", "The piece is tiny but hyperactive."], "know": "It became a favourite showpiece for many instruments.", "takeaway": "Sometimes music imitates movement so well that you can almost see it."}, {"title": "Pictures at an Exhibition: Promenade", "composer": "Modest Mussorgsky", "year": "1874", "period": "Romantic / Russian nationalist", "duration": "~2 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mussorgsky%20-%20Pictures%20at%20an%20Exhibition%20-%20Promenade.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Pictures_at_an_Exhibition", "why": "The Promenade is the listener walking through a gallery. It gives the whole work its human frame.", "listen": ["The meter feels slightly irregular, like walking.", "The melody is bold and plainspoken.", "It returns in different forms through the work.", "The music creates space between images."], "know": "Pictures at an Exhibition is one of the most famous examples of music inspired by visual art.", "takeaway": "Music can make you walk through imaginary rooms."}, {"title": "Pictures at an Exhibition: The Great Gate of Kiev", "composer": "Modest Mussorgsky", "year": "1874 / orchestrated 1922 by Ravel", "period": "Romantic / Russian nationalist", "duration": "~5–6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Mussorgsky%20-%20Pictures%20at%20an%20Exhibition%20-%20The%20Great%20Gate%20of%20Kiev.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Pictures_at_an_Exhibition", "why": "The finale turns architecture into sound: bells, grandeur, procession and monumental arrival.", "listen": ["The main theme feels broad and architectural.", "Bell-like writing creates ceremony.", "The music grows in scale.", "The ending feels like entering a huge public square."], "know": "Ravel’s orchestration helped make the work an orchestral classic.", "takeaway": "Music can make a building feel larger than life."}, {"title": "Adagio for Strings", "composer": "Samuel Barber", "year": "1936", "period": "20th-century lyricism", "duration": "~8–9 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Barber%20-%20Adagio%20for%20Strings.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Adagio_for_Strings", "why": "It builds grief through a long, rising line that seems to stretch until it cannot bear any more.", "listen": ["The melody climbs slowly and painfully.", "The harmony intensifies without rushing.", "The climax feels like breaking point.", "The silence after the climax matters."], "know": "It became one of the twentieth century’s most recognised pieces for mourning and remembrance.", "takeaway": "A single long line can feel like collective grief."}, {"title": "Rhapsody in Blue", "composer": "George Gershwin", "year": "1924", "period": "Jazz-influenced classical / American modernism", "duration": "~16 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Gershwin%20-%20Rhapsody%20in%20Blue.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Rhapsody_in_Blue", "why": "Gershwin blends concert music, jazz language and urban energy into a piece that sounds unmistakably American.", "listen": ["The opening clarinet glissando is iconic.", "Piano and orchestra trade personalities.", "The music shifts between swagger, lyricism and bustle.", "The structure feels episodic, like city life."], "know": "It became a symbol of 1920s American modernity.", "takeaway": "A city can have a sound."}, {"title": "Appalachian Spring: Simple Gifts", "composer": "Aaron Copland", "year": "1944", "period": "American modernism", "duration": "~3–5 min excerpt", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Copland%20-%20Appalachian%20Spring%20-%20Simple%20Gifts.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Appalachian_Spring", "why": "Copland turns a Shaker tune into spacious American optimism: open intervals, clear textures and gentle transformation.", "listen": ["The tune is simple and memorable.", "The orchestration leaves lots of open space.", "Variations grow naturally from the melody.", "The mood is hopeful without being flashy."], "know": "It is one of the defining sounds of American concert music.", "takeaway": "National style can be built from space as much as melody."}, {"title": "Canon in D", "composer": "Johann Pachelbel", "year": "late 17th century", "period": "Baroque", "duration": "~4–6 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Pachelbel%20-%20Canon%20in%20D.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Canon_in_D_major_(Pachelbel)", "why": "It became famous because its repeating bass and layered entries create a feeling of calm inevitability.", "listen": ["The bass pattern repeats throughout.", "Voices enter one after another in canon.", "The texture gradually becomes more active.", "The harmony feels stable and satisfying."], "know": "It is one of the most common pieces at weddings and one of Baroque music’s biggest popular hits.", "takeaway": "Predictability can be beautiful when the surface keeps changing."}, {"title": "Adagio in G minor", "composer": "Remo Giazotto after Tomaso Albinoni", "year": "20th century based on Baroque style", "period": "Neo-Baroque / popular classical", "duration": "~8 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Albinoni%20-%20Adagio%20in%20G%20minor.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Adagio_in_G_minor", "why": "Although often linked to Albinoni, the piece is largely a twentieth-century creation. Its power lies in solemn, slow-building melancholy.", "listen": ["The organ or continuo creates a dark foundation.", "The melody rises in long emotional lines.", "The piece uses Baroque language for modern sentiment.", "The climax is restrained but intense."], "know": "It is a good reminder that classical fame sometimes comes with messy attribution.", "takeaway": "The story behind a piece can be as slippery as the music is beautiful."}, {"title": "O Fortuna from Carmina Burana", "composer": "Carl Orff", "year": "1935–1936", "period": "20th century", "duration": "~2–3 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Orff%20-%20Carmina%20Burana%20-%20O%20Fortuna.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Carmina_Burana_(Orff)", "why": "O Fortuna is blunt, huge and ritualistic. It became the default sound of apocalyptic drama.", "listen": ["The opening hits with massive choral force.", "The rhythm is simple and pounding.", "The dynamics create shock through contrast.", "The Latin text adds ritual weight."], "know": "It is one of the most reused classical excerpts in trailers and popular media.", "takeaway": "Sometimes impact beats subtlety."}, {"title": "Spiegel im Spiegel", "composer": "Arvo Pärt", "year": "1978", "period": "Holy minimalism", "duration": "~8–10 min", "source": "Wikimedia Commons / public-domain or freely licensed recording search", "audio": "https://commons.wikimedia.org/wiki/Special:FilePath/Part%20-%20Spiegel%20im%20Spiegel.ogg", "sourceUrl": "https://commons.wikimedia.org/wiki/Category:Spiegel_im_Spiegel", "why": "Pärt creates stillness with extreme simplicity: stepwise melody and bell-like piano triads. It feels like time slowing down.", "listen": ["The melody moves mostly step by step.", "The piano repeats calm triadic patterns.", "Silence and resonance are essential.", "The emotional effect comes from patience."], "know": "It is one of the most famous late twentieth-century minimalist works.", "takeaway": "Stillness can be more intense than movement."}];
const PERIODS = {"Baroque": {"years": "c. 1600–1750", "simple": "Drama, pattern, ornament, basso continuo, counterpoint and strong rhythmic drive.", "listenFor": ["repeating bass lines", "imitation between voices", "clear pulse", "ornamented melodies"]}, "Classical": {"years": "c. 1750–1820", "simple": "Balance, clarity, elegant phrase structure and dramatic form without excessive heaviness.", "listenFor": ["symmetrical phrases", "clear themes", "sonata-form contrast", "transparent textures"]}, "Classical / Romantic transition": {"years": "late 18th–early 19th century", "simple": "Classical structure under emotional pressure, especially in Beethoven.", "listenFor": ["motifs developed intensely", "strong contrasts", "dramatic silence", "larger emotional scale"]}, "Romantic": {"years": "c. 1810–1900", "simple": "Personal emotion, richer harmony, expanded forms, virtuosity, nationalism and atmosphere.", "listenFor": ["big melodies", "rubato", "expanded orchestra", "strong mood or story"]}, "Impressionism": {"years": "late 19th–early 20th century", "simple": "Colour, atmosphere, ambiguity and harmony that often floats rather than drives forward.", "listenFor": ["shimmering textures", "unresolved harmony", "instrumental colour", "fluid rhythm"]}, "Modernism": {"years": "early 20th century", "simple": "Rhythmic shock, new harmonies, fragmentation, experimentation and rejection of old comfort.", "listenFor": ["irregular accents", "unusual timbres", "dissonance", "primitive or mechanical energy"]}, "Modern / Late Romantic": {"years": "early 20th century", "simple": "Large Romantic orchestras meeting modern rhythm, colour and scale.", "listenFor": ["huge orchestration", "bold rhythm", "mythic themes", "cinematic sweep"]}, "Late Romantic / Verismo": {"years": "late 19th–early 20th century", "simple": "Opera focused on direct emotion, theatrical realism and intense vocal lines.", "listenFor": ["soaring vocal climaxes", "orchestral emotion", "direct drama", "memorable arias"]}, "Jazz-influenced classical / American modernism": {"years": "20th century", "simple": "Concert music absorbing jazz rhythm, harmony and urban energy.", "listenFor": ["blue notes", "syncopation", "piano-orchestra dialogue", "city-like episodes"]}, "American modernism": {"years": "20th century", "simple": "A clearer, spacious modern sound often tied to landscape, national identity and open intervals.", "listenFor": ["wide intervals", "clear textures", "folk material", "open space"]}, "20th-century lyricism": {"years": "20th century", "simple": "Modern-era music that keeps melody and emotional directness at the centre.", "listenFor": ["long lines", "rich strings", "slow climaxes", "direct feeling"]}, "Holy minimalism": {"years": "late 20th century", "simple": "Spare, spiritual, slow-moving music built from simple materials and resonance.", "listenFor": ["silence", "bell-like harmony", "slow repetition", "patient unfolding"]}, "Neo-Baroque / popular classical": {"years": "20th century in older style", "simple": "Modern music borrowing Baroque gestures for accessible, dramatic effect.", "listenFor": ["slow ground bass", "organ-like solemnity", "long melody", "stylised grief"]}, "Bel canto / Classical-Romantic": {"years": "early 19th century", "simple": "Vocal agility, clarity, comic timing and elegant operatic display.", "listenFor": ["patter singing", "clear vocal lines", "comic energy", "orchestral sparkle"]}, "Romantic / Russian nationalist": {"years": "19th century Russia", "simple": "Colourful orchestration, folk influence, storytelling and distinctive national character.", "listenFor": ["orchestral colour", "folk-like melodies", "vivid scenes", "strong narrative"]}};
const COMPOSERS = {"Johann Sebastian Bach": {"life": "1685–1750", "why": "The supreme architect of counterpoint, structure and sacred/instrumental depth.", "timeline": ["1685 born in Eisenach", "1708–1717 works in Weimar", "1717–1723 works in Köthen, writes much instrumental music", "1723 becomes Thomaskantor in Leipzig", "1750 dies in Leipzig"]}, "Antonio Vivaldi": {"life": "1678–1741", "why": "Venetian Baroque composer famous for concertos, rhythmic energy and vivid instrumental colour.", "timeline": ["1678 born in Venice", "Works with the Ospedale della Pietà", "1723 publishes The Four Seasons", "Later travels and works as composer/impresario", "1741 dies in Vienna"]}, "George Frideric Handel": {"life": "1685–1759", "why": "Master of opera, oratorio and public musical drama.", "timeline": ["1685 born in Halle", "Moves to London in 1712", "1741 composes Messiah", "Becomes central to British musical life", "1759 dies in London"]}, "Wolfgang Amadeus Mozart": {"life": "1756–1791", "why": "A composer of astonishing fluency, dramatic instinct and formal balance.", "timeline": ["1756 born in Salzburg", "Child prodigy across Europe", "1781 moves to Vienna", "1786–1791 major operas and late symphonies", "1791 dies in Vienna"]}, "Ludwig van Beethoven": {"life": "1770–1827", "why": "Expanded Classical forms into a more dramatic, personal and heroic musical language.", "timeline": ["1770 born in Bonn", "1792 moves to Vienna", "1802 Heiligenstadt Testament", "1804–1808 middle-period breakthroughs", "1824 Ninth Symphony", "1827 dies in Vienna"]}, "Frédéric Chopin": {"life": "1810–1849", "why": "The poet of the piano: intimate, refined, technically demanding and harmonically rich.", "timeline": ["1810 born near Warsaw", "1830 leaves Poland", "1830s builds career in Paris", "1838–1839 Majorca period with George Sand", "1849 dies in Paris"]}, "Franz Liszt": {"life": "1811–1886", "why": "Virtuoso pianist, showman, innovator and creator of dazzling piano textures.", "timeline": ["1811 born in Hungary", "1830s becomes legendary touring virtuoso", "1848 settles in Weimar", "1850 publishes Liebesträume", "1886 dies in Bayreuth"]}, "Franz Schubert": {"life": "1797–1828", "why": "A master of melody, song, intimacy and bittersweet harmonic turns.", "timeline": ["1797 born in Vienna", "1815 writes Erlkönig", "1819 writes Trout Quintet", "1820s major songs and chamber music", "1828 dies in Vienna"]}, "Felix Mendelssohn": {"life": "1809–1847", "why": "Composer of elegance, clarity, fairy-light orchestration and Romantic lyricism.", "timeline": ["1809 born in Hamburg", "1826 writes Midsummer Night’s Dream overture", "1829 revives Bach’s St Matthew Passion", "1842 writes Wedding March music", "1847 dies in Leipzig"]}, "Johannes Brahms": {"life": "1833–1897", "why": "A Romantic composer with deep respect for classical structure and dense emotional craft.", "timeline": ["1833 born in Hamburg", "1853 meets Robert and Clara Schumann", "1869 Hungarian Dances published", "1876 First Symphony", "1897 dies in Vienna"]}, "Pyotr Ilyich Tchaikovsky": {"life": "1840–1893", "why": "A master of melody, ballet, emotional directness and orchestral drama.", "timeline": ["1840 born in Votkinsk", "1875–1876 composes Swan Lake", "1880 writes 1812 Overture", "1892 The Nutcracker premieres", "1893 dies in Saint Petersburg"]}, "Antonín Dvořák": {"life": "1841–1904", "why": "Blended Czech musical character with symphonic craft and memorable melody.", "timeline": ["1841 born near Prague", "1878 Slavonic Dances bring fame", "1892 moves to America", "1893 writes New World Symphony", "1904 dies in Prague"]}, "Claude Debussy": {"life": "1862–1918", "why": "Changed music through colour, ambiguity, atmosphere and new harmonic language.", "timeline": ["1862 born near Paris", "1894 Prélude à l'après-midi d'un faune", "1905 La mer", "1910s late works", "1918 dies in Paris"]}, "Erik Satie": {"life": "1866–1925", "why": "Eccentric French composer whose spare, ironic simplicity anticipated later minimal and ambient thinking.", "timeline": ["1866 born in Honfleur", "1888 Gymnopédies", "1890 Gnossiennes", "1910s associated with Paris avant-garde", "1925 dies in Paris"]}, "Maurice Ravel": {"life": "1875–1937", "why": "A meticulous colourist and orchestrator with elegance, precision and modern bite.", "timeline": ["1875 born in Ciboure", "1899 writes Pavane", "1908 Gaspard de la nuit", "1928 Boléro", "1937 dies in Paris"]}, "Gustav Holst": {"life": "1874–1934", "why": "British composer best known for orchestral colour and astrological imagination in The Planets.", "timeline": ["1874 born in Cheltenham", "1914–1917 composes The Planets", "1918 The Planets first performed privately", "Later teaches and composes widely", "1934 dies in London"]}, "Igor Stravinsky": {"life": "1882–1971", "why": "One of the defining modernist composers, famous for rhythm, reinvention and stylistic sharpness.", "timeline": ["1882 born near Saint Petersburg", "1910 Firebird premieres", "1913 Rite of Spring premieres", "1920s neoclassical period", "1971 dies in New York"]}, "Georges Bizet": {"life": "1838–1875", "why": "Composer of Carmen, one of opera’s most enduring combinations of melody, rhythm and theatre.", "timeline": ["1838 born in Paris", "1875 Carmen premieres", "Dies three months after Carmen’s premiere", "Carmen later becomes one of the world’s most performed operas"]}, "Gioachino Rossini": {"life": "1792–1868", "why": "Master of comic opera, vocal brilliance, crescendos and theatrical timing.", "timeline": ["1792 born in Pesaro", "1816 The Barber of Seville premieres", "1829 William Tell premieres", "Retires early from opera", "1868 dies near Paris"]}, "Giacomo Puccini": {"life": "1858–1924", "why": "Late Romantic opera composer with unmatched instinct for theatrical melody and emotional climax.", "timeline": ["1858 born in Lucca", "1896 La bohème", "1904 Madama Butterfly", "1924 dies before completing Turandot", "1926 Turandot premieres posthumously"]}, "Richard Wagner": {"life": "1813–1883", "why": "Revolutionised opera through leitmotifs, expanded harmony and mythic scale.", "timeline": ["1813 born in Leipzig", "1859 Tristan und Isolde completed", "1876 Bayreuth Festival opens with Ring cycle", "1883 dies in Venice"]}, "Edvard Grieg": {"life": "1843–1907", "why": "Norwegian Romantic composer known for lyricism, folk colour and miniature atmosphere.", "timeline": ["1843 born in Bergen", "1867 Piano Concerto", "1875 Peer Gynt incidental music", "1907 dies in Bergen"]}, "Nikolai Rimsky-Korsakov": {"life": "1844–1908", "why": "Russian master of orchestration, colour and fantastical storytelling.", "timeline": ["1844 born in Tikhvin", "Member of The Five", "1888 Scheherazade", "1899–1900 Tale of Tsar Saltan", "1908 dies near Saint Petersburg"]}, "Modest Mussorgsky": {"life": "1839–1881", "why": "Russian composer of raw originality, vivid character and bold musical storytelling.", "timeline": ["1839 born in Karevo", "1874 writes Pictures at an Exhibition", "Works on Boris Godunov", "1881 dies in Saint Petersburg"]}, "Samuel Barber": {"life": "1910–1981", "why": "American composer known for lyrical intensity and emotional directness.", "timeline": ["1910 born in Pennsylvania", "1936 writes string quartet movement later arranged as Adagio", "1938 Toscanini conducts Adagio for Strings", "1981 dies in New York"]}, "George Gershwin": {"life": "1898–1937", "why": "Brought jazz, Broadway and concert music into a distinctive American voice.", "timeline": ["1898 born in Brooklyn", "1924 Rhapsody in Blue premieres", "1928 An American in Paris", "1935 Porgy and Bess", "1937 dies in Hollywood"]}, "Aaron Copland": {"life": "1900–1990", "why": "Helped define a spacious American orchestral sound.", "timeline": ["1900 born in Brooklyn", "1930s develops populist style", "1944 Appalachian Spring", "Later teaches, conducts and writes widely", "1990 dies in New York"]}, "Johann Pachelbel": {"life": "1653–1706", "why": "German Baroque composer now best known for Canon in D.", "timeline": ["1653 born in Nuremberg", "Works in Erfurt, Stuttgart and elsewhere", "Writes keyboard and sacred music", "1706 dies in Nuremberg"]}, "Remo Giazotto after Tomaso Albinoni": {"life": "1910–1998 / Albinoni 1671–1751", "why": "The famous Adagio is mostly Giazotto’s twentieth-century construction in Baroque style.", "timeline": ["Albinoni active in Venice in the Baroque era", "Giazotto was a twentieth-century musicologist", "1950s Adagio in G minor published", "Attribution remains widely misunderstood"]}, "Carl Orff": {"life": "1895–1982", "why": "German composer best known for direct rhythm, chorus and theatrical impact in Carmina Burana.", "timeline": ["1895 born in Munich", "1935–1936 writes Carmina Burana", "1937 premiere", "Later develops music education approach", "1982 dies in Munich"]}, "Arvo Pärt": {"life": "1935–", "why": "Estonian composer associated with spiritual minimalism and tintinnabuli style.", "timeline": ["1935 born in Estonia", "1970s develops tintinnabuli style", "1978 writes Spiegel im Spiegel", "Later becomes one of the most performed living composers"]}};
const APP_VERSION = "1.0";
const STORAGE = { saved: "classicalwise_saved_v1", listened: "classicalwise_listened_v1" };
const state = { section: "today", query: "", period: "All" };

const $ = s => document.querySelector(s);
const $$ = s => Array.from(document.querySelectorAll(s));

function safeParse(k,f){try{const r=localStorage.getItem(k);return r?JSON.parse(r):f}catch{return f}}
function saveJSON(k,v){localStorage.setItem(k,JSON.stringify(v))}
function getSaved(){return new Set(safeParse(STORAGE.saved,[]))}
function setSaved(s){saveJSON(STORAGE.saved,[...s])}
function getListened(){return safeParse(STORAGE.listened,{})}
function setListened(o){saveJSON(STORAGE.listened,o)}
function id(p){return `${p.composer}::${p.title}`}
function esc(s){return String(s??"").replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"}[c]))}
function norm(s){return String(s||"").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"")}
function todayKey(){const d=new Date();return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`}
function displayDate(){return new Date().toLocaleDateString(undefined,{weekday:"long",year:"numeric",month:"long",day:"numeric"})}
function dailyIndex(){const key=todayKey();let h=0;for(let i=0;i<key.length;i++)h=((h<<5)-h+key.charCodeAt(i))|0;return Math.abs(h)%PIECES.length}
function todayPiece(){return PIECES[dailyIndex()]}
function periodList(){return [...new Set(PIECES.map(p=>p.period).filter(Boolean))].sort()}
function findPiece(x){return PIECES.find(p=>id(p)===x)}
function toggleSaved(p){const s=getSaved();s.has(id(p))?s.delete(id(p)):s.add(id(p));setSaved(s);render()}
function markListened(p){const l=getListened();l[id(p)] = new Date().toISOString();setListened(l)}
function filtered(){const q=norm(state.query);return PIECES.filter(p=>{const periodOk=state.period==="All"||p.period===state.period;const text=norm([p.title,p.composer,p.year,p.period,p.why,p.know,p.takeaway,...(p.listen||[])].join(" "));return periodOk && (!q || text.includes(q));})}

function audioBlock(p, compact=false){
  const source = esc(p.sourceUrl || "#");
  const audio = esc(p.audio || "");
  return `<div class="audio-box">
    <audio controls preload="${compact ? "none" : "metadata"}" data-piece="${esc(id(p))}">
      <source src="${audio}" type="audio/ogg">
      <source src="${audio}" type="audio/mpeg">
    </audio>
    <div class="audio-fallback">
      <span>Audio not loading?</span>
      <a href="${source}" target="_blank" rel="noopener noreferrer">Open recording source</a>
    </div>
  </div>`;
}

function pieceCard(p, mode="full"){
  const saved=getSaved().has(id(p));
  const listened=Boolean(getListened()[id(p)]);
  return `<article class="piece-card ${mode==="today" ? "today-card" : ""}">
    <div class="piece-top">
      <div>
        <div class="eyebrow">${esc(p.period)} · ${esc(p.year)} · ${esc(p.duration)}</div>
        <h2>${esc(p.title)}</h2>
        <p class="composer">by ${esc(p.composer)}</p>
      </div>
      <div class="status-stack">
        ${listened?`<span class="status-pill">Listened</span>`:""}
        <button class="save-btn ${saved?"active":""}" data-action="save" data-piece="${esc(id(p))}">${saved?"Saved ★":"Save ★"}</button>
      </div>
    </div>
    ${audioBlock(p, mode==="compact")}
    ${mode==="compact" ? `<p class="why-mini">${esc(p.why)}</p>` : `
      <section class="lesson-block"><div class="eyebrow">Why it is special</div><p>${esc(p.why)}</p></section>
      <section class="lesson-block"><div class="eyebrow">What to listen for</div><ul>${(p.listen||[]).map(x=>`<li>${esc(x)}</li>`).join("")}</ul></section>
      <section class="lesson-block"><div class="eyebrow">Why you should know this</div><p>${esc(p.know)}</p></section>
      <section class="takeaway"><div class="eyebrow">Teacher takeaway</div><p>${esc(p.takeaway)}</p></section>
      <p class="small-note">Recording links are from public-domain / freely licensed source pages where possible. If direct audio fails, use “Open recording source”.</p>
    `}
  </article>`;
}

function controls(){
 return `<section class="controls">
   <input id="searchBox" class="search-input" type="search" placeholder="Search piece, composer, period, idea..." value="${esc(state.query)}">
   <select id="periodFilter" class="select-control">
     <option value="All">All periods</option>
     ${periodList().map(p=>`<option value="${esc(p)}" ${state.period===p?"selected":""}>${esc(p)}</option>`).join("")}
   </select>
   <button id="clearFilters" class="secondary-btn">Clear</button>
 </section>`;
}

function renderToday(){
 const p=todayPiece();
 $("#app").innerHTML = `<section class="hero">
   <div><div class="eyebrow">ClassicalWise v${APP_VERSION} · ${displayDate()}</div><h1>Today’s piece</h1><p>One famous classical work a day. Listen first, then understand what made it last.</p></div>
   <button class="secondary-btn" data-nav="library">Explore library</button>
 </section>${pieceCard(p,"today")}`;
 bindAudioEvents();
}

function renderLibrary(savedOnly=false){
 const saved=getSaved();
 const arr=filtered().filter(p=>!savedOnly||saved.has(id(p)));
 $("#app").innerHTML = `<section class="page-head"><div><h1>${savedOnly?"Saved pieces":"Library"}</h1><p>${arr.length} piece${arr.length===1?"":"s"}. Curated famous works with full-listen source links and plain-English notes.</p></div></section>${controls()}<section class="grid">${arr.map(p=>pieceCard(p,"compact")).join("")||`<div class="empty-state">${savedOnly?"No saved pieces yet.":"No pieces found."}</div>`}</section>`;
 bindAudioEvents();
}

function renderComposers(){
 const names=Object.keys(COMPOSERS).sort();
 $("#app").innerHTML = `<section class="page-head"><div><h1>Composers</h1><p>Fast context so the names stop feeling like marble statues.</p></div></section><section class="timeline-grid">${names.map(n=>{const c=COMPOSERS[n];return `<article class="timeline-card"><div class="eyebrow">${esc(c.life)}</div><h2>${esc(n)}</h2><p>${esc(c.why)}</p><ol>${(c.timeline||[]).map(x=>`<li>${esc(x)}</li>`).join("")}</ol></article>`}).join("")}</section>`;
}

function renderPeriods(){
 const keys=Object.keys(PERIODS).sort();
 $("#app").innerHTML = `<section class="page-head"><div><h1>Periods explained</h1><p>The minimum useful context. No conservatory fog.</p></div></section><section class="learn-grid">${keys.map(k=>{const p=PERIODS[k];return `<article class="learn-card"><div class="eyebrow">${esc(p.years)}</div><h2>${esc(k)}</h2><p>${esc(p.simple)}</p><div class="mini-list">${(p.listenFor||[]).map(x=>`<span>${esc(x)}</span>`).join("")}</div><button class="secondary-btn" data-period="${esc(k)}">Hear pieces</button></article>`}).join("")}</section>`;
}

function renderListenGuide(){
 const items=[
  ["Do not start with biography","For the first listen, biography can become noise. Ask: what does the music make me expect, and when does it surprise me?"],
  ["Listen for the hook","In classical music the hook may be a motif, rhythm, texture, instrument colour or harmonic mood, not only a melody."],
  ["Notice repetition","When something repeats, ask what changed: instrument, volume, harmony, register, speed, emotional meaning."],
  ["Use the first two minutes well","You do not need to understand a whole symphony immediately. The opening usually teaches you the rules of the piece."],
  ["Follow tension and release","Classical music often works by delaying arrival. The question is not only what happens, but how long the composer makes you wait."],
  ["Let one observation be enough","A useful listen can be one real thing noticed: a rhythm, a colour, a return, a silence, a climax."]
 ];
 $("#app").innerHTML = `<section class="page-head"><div><h1>How to listen</h1><p>A simple listening framework for normal humans with ears, not just people wearing scarves indoors.</p></div></section><section class="learn-grid">${items.map(i=>`<article class="learn-card"><h2>${esc(i[0])}</h2><p>${esc(i[1])}</p></article>`).join("")}</section>`;
}

function renderAbout(){
 const saved=getSaved().size;
 const listened=Object.keys(getListened()).length;
 $("#app").innerHTML = `<section class="about-card"><h1>About ClassicalWise</h1><p>ClassicalWise is a daily classical music teacher: one famous piece per day, full-listen source, and clear notes on why it matters.</p><div class="stat-grid"><div><strong>${PIECES.length}</strong><span>pieces in v1.0</span></div><div><strong>${listened}</strong><span>listened</span></div><div><strong>${saved}</strong><span>saved</span></div></div><p class="small-note">Direct audio from public/free sources can vary by browser and host. The app includes source fallback links by design.</p></section>`;
}

function render(){
 $$(".nav-btn").forEach(b=>b.classList.toggle("active", b.dataset.nav===state.section));
 if(state.section==="today")renderToday();
 if(state.section==="library")renderLibrary(false);
 if(state.section==="saved")renderLibrary(true);
 if(state.section==="composers")renderComposers();
 if(state.section==="periods")renderPeriods();
 if(state.section==="listen")renderListenGuide();
 if(state.section==="about")renderAbout();
}

function setSection(s){state.section=s;state.query="";state.period="All";render()}

function handleClick(e){
 const t=e.target.closest("button,[data-nav],[data-action],[data-period]");
 if(!t)return;
 if(t.dataset.period){state.section="library";state.period=t.dataset.period;state.query="";render();return;}
 if(t.dataset.nav){setSection(t.dataset.nav);return;}
 if(t.id==="clearFilters"){state.query="";state.period="All";render();return;}
 const p=findPiece(t.dataset.piece);
 if(t.dataset.action==="save"&&p)toggleSaved(p);
}

function handleInput(e){if(e.target?.id==="searchBox"){state.query=e.target.value||"";state.section==="saved"?renderLibrary(true):renderLibrary(false)}}
function handleChange(e){if(e.target?.id==="periodFilter"){state.period=e.target.value||"All";state.section==="saved"?renderLibrary(true):renderLibrary(false)}}

function bindAudioEvents(){
 $$("audio[data-piece]").forEach(a=>{
   a.addEventListener("play",()=>{const p=findPiece(a.dataset.piece); if(p) markListened(p);},{once:true});
   a.addEventListener("error",()=>{a.closest(".audio-box")?.classList.add("audio-failed");});
 });
}

function boot(){
 document.body.innerHTML = `<div class="app-shell">
  <header class="topbar">
    <div class="brand"><div class="logo-mark">C</div><div><strong>ClassicalWise</strong><span>Daily music teacher</span></div></div>
    <nav class="nav">
      <button class="nav-btn active" data-nav="today">Today</button>
      <button class="nav-btn" data-nav="library">Library</button>
      <button class="nav-btn" data-nav="saved">Saved</button>
      <button class="nav-btn" data-nav="composers">Composers</button>
      <button class="nav-btn" data-nav="periods">Periods</button>
      <button class="nav-btn" data-nav="listen">How to listen</button>
      <button class="nav-btn" data-nav="about">About</button>
    </nav>
  </header>
  <main id="app"></main>
 </div>`;
 document.addEventListener("click",handleClick);
 document.addEventListener("input",handleInput);
 document.addEventListener("change",handleChange);
 if("serviceWorker" in navigator)navigator.serviceWorker.register("./service-worker.js").catch(()=>{});
 render();
}

document.addEventListener("DOMContentLoaded",boot);
